// ═══════════════════════════════════════════════════════════════════════════
// PROCESADOR DE FIRMA DIGITAL - VERSIÓN ULTRA ROBUSTA
// Maneja: Zonas horarias, validaciones, formatos, edge cases
// ═══════════════════════════════════════════════════════════════════════════

const input = $input.first().json;
const body = input.body || input;

// ═══════════════════════════════════════════════════════════════════════════
// 1. EXTRACCIÓN DE DATOS CON FALLBACKS
// ═══════════════════════════════════════════════════════════════════════════
const name = (body.name || body.clientName || body.nombre || '').trim();
const docId = (body.docId || body.clientDocId || body.documento || body.id || '').trim();
const address = (body.address || body.clientAddress || body.direccion || body.domicilio || '').trim();
const email = (body.email || body.clientEmail || body.correo || '').trim().toLowerCase();
const token = body.token || body.accessToken || '';
const signatureBase64 = body.signature || body.signatureDataUri || body.firma || '';
const signatureType = body.signatureType || body.tipoFirma || 'draw';
const userAgent = body.userAgent || body.navegador || '';

// ═══════════════════════════════════════════════════════════════════════════
// 2. VALIDACIONES EXHAUSTIVAS
// ═══════════════════════════════════════════════════════════════════════════
const errores = [];

if (!name) errores.push('Nombre completo');
if (!docId) errores.push('Número de documento');
if (!email) errores.push('Correo electrónico');

// Validar formato de email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (email && !emailRegex.test(email)) {
  errores.push('Formato de email inválido');
}

// Validar firma
if (!signatureBase64) {
  errores.push('Firma digital');
} else if (!signatureBase64.startsWith('data:image')) {
  errores.push('Formato de firma inválido (debe ser imagen)');
}

if (errores.length > 0) {
  return [{ 
    json: { 
      success: false, 
      error: 'Datos incompletos o inválidos', 
      message: `Campos con problemas: ${errores.join(', ')}`,
      camposFaltantes: errores
    } 
  }];
}

// ═══════════════════════════════════════════════════════════════════════════
// 3. GENERACIÓN DE ID DE CONTRATO ÚNICO
// ═══════════════════════════════════════════════════════════════════════════
const timestamp = Date.now();
const randomPart = Math.random().toString(36).substring(2, 6).toUpperCase();
const contractId = `NX-${timestamp.toString(36).toUpperCase()}-${randomPart}`;

// ═══════════════════════════════════════════════════════════════════════════
// 4. MANEJO ROBUSTO DE FECHA Y HORA - ZONA HORARIA COLOMBIA
// ═══════════════════════════════════════════════════════════════════════════
const TIMEZONE = 'America/Bogota';

// Obtener fecha actual en Colombia (ignoramos la fecha del cliente por seguridad)
const ahora = new Date();

// Función para formatear fecha en español Colombia
function formatearFechaColombia(fecha) {
  try {
    // Método 1: Intl.DateTimeFormat (más confiable)
    const opcionesFecha = {
      timeZone: TIMEZONE,
      weekday: 'long',
      day: 'numeric',
      month: 'long',
      year: 'numeric'
    };

    const opcionesHora = {
      timeZone: TIMEZONE,
      hour: 'numeric',
      minute: '2-digit',
      hour12: true
    };

    const fechaStr = fecha.toLocaleDateString('es-CO', opcionesFecha);
    const horaStr = fecha.toLocaleTimeString('es-CO', opcionesHora);

    // Capitalizar primera letra del día
    const fechaCapitalizada = fechaStr.charAt(0).toUpperCase() + fechaStr.slice(1);

    return {
      fechaCompleta: `${fechaCapitalizada} a las ${horaStr}`,
      fechaCorta: fecha.toLocaleDateString('es-CO', { 
        timeZone: TIMEZONE, 
        day: 'numeric', 
        month: 'long', 
        year: 'numeric' 
      }),
      horaCorta: horaStr,
      iso: fecha.toISOString(),
      timestamp: fecha.getTime()
    };
  } catch (error) {
    // Fallback manual si Intl falla
    const meses = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 
                   'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];
    const dias = ['domingo', 'lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado'];

    // Ajustar manualmente a UTC-5 (Colombia)
    const offsetColombia = -5 * 60; // minutos
    const offsetLocal = fecha.getTimezoneOffset();
    const diferencia = offsetColombia - offsetLocal;
    const fechaColombia = new Date(fecha.getTime() + diferencia * 60 * 1000);

    const dia = dias[fechaColombia.getDay()];
    const diaNum = fechaColombia.getDate();
    const mes = meses[fechaColombia.getMonth()];
    const año = fechaColombia.getFullYear();

    let hora = fechaColombia.getHours();
    const minutos = fechaColombia.getMinutes().toString().padStart(2, '0');
    const ampm = hora >= 12 ? 'p.m.' : 'a.m.';
    hora = hora % 12 || 12;

    return {
      fechaCompleta: `${dia.charAt(0).toUpperCase() + dia.slice(1)}, ${diaNum} de ${mes} de ${año} a las ${hora}:${minutos} ${ampm}`,
      fechaCorta: `${diaNum} de ${mes} de ${año}`,
      horaCorta: `${hora}:${minutos} ${ampm}`,
      iso: fecha.toISOString(),
      timestamp: fecha.getTime()
    };
  }
}

const fechaInfo = formatearFechaColombia(ahora);

// ═══════════════════════════════════════════════════════════════════════════
// 5. EXTRACCIÓN DE INFORMACIÓN DEL REQUEST
// ═══════════════════════════════════════════════════════════════════════════
const headers = input.headers || {};

// IP del cliente (considerando proxies)
const ipAddress = headers['x-forwarded-for']?.split(',')[0]?.trim() || 
                  headers['x-real-ip'] || 
                  headers['cf-connecting-ip'] || // Cloudflare
                  headers['x-client-ip'] ||
                  'No disponible';

// País/Región si está disponible (Cloudflare)
const country = headers['cf-ipcountry'] || 'N/A';

// ═══════════════════════════════════════════════════════════════════════════
// 6. SANITIZACIÓN DE DATOS PARA PDF/EMAIL
// ═══════════════════════════════════════════════════════════════════════════
function sanitizarTexto(texto) {
  if (!texto) return '';
  return texto
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// ═══════════════════════════════════════════════════════════════════════════
// 7. RETORNO DE DATOS COMPLETOS
// ═══════════════════════════════════════════════════════════════════════════
return [{
  json: {
    // Estado
    success: true,

    // Identificadores
    contractId: contractId,

    // Datos del cliente (sanitizados)
    clientName: sanitizarTexto(name),
    clientDocId: sanitizarTexto(docId),
    clientAddress: sanitizarTexto(address) || 'No especificado',
    clientEmail: email,
    token: token,

    // Firma
    signatureDataUri: signatureBase64,
    signatureType: signatureType,

    // Fechas (múltiples formatos)
    signedAt: fechaInfo.iso,
    signedAtTimestamp: fechaInfo.timestamp,
    formattedDate: fechaInfo.fechaCompleta,
    fechaCorta: fechaInfo.fechaCorta,
    horaCorta: fechaInfo.horaCorta,
    timezone: TIMEZONE,

    // Metadatos de seguridad
    ipAddress: ipAddress,
    country: country,
    userAgent: userAgent,

    // Info adicional para auditoría
    metadata: {
      processedAt: new Date().toISOString(),
      n8nNodeVersion: '2.0',
      signatureSize: signatureBase64.length,
      validationsPassed: true
    }
  }
}];

